## **Complete Guide: `pi` Custom Tool Development**

### 1. **Core Concepts & Architecture**

```typescript
import { withFileMutationQueue, createReadTool, createBashTool } from "@mariozechner/pi-coding-agent";

// Key principle: All tools run in parallel by default, so you MUST use 
// withFileMutationQueue when mutating files to prevent race conditions
```

### 2. **Building Custom Tools**

```typescript
import { Type, StringEnum } from "@sinclair/typebox";
import { Text } from "@mariozechner/pi-tui";
import { withFileMutationQueue } from "@mariozechner/pi-coding-agent";
import { mkdir, readFile, writeFile } from "node:fs/promises";
import { dirname, resolve } from "node:path";

// ===== Example 1: Simple Todo List Tool =====

pi.registerTool({
  name: "todo-manage",
  label: "Todo List Manager",
  description: "Add, list, and complete tasks in your project",
  promptSnippet: "Use this tool to maintain a todo list of pending work items",
  promptGuidelines: [
    "Use this tool for todo planning instead of direct file edits",
    "Complete items by setting action to 'complete'",
    "Always track task progress using this tool"
  ],
  parameters: Type.Object({
    action: StringEnum(["add", "list", "complete", "clear"]),
    text: Type.Optional(Type.String()),
  }),

  async execute(toolCallId, params, signal, onUpdate, ctx) {
    // Handle cancellation
    if (signal?.aborted) {
      return { content: [{ type: "text", text: "Cancelled" }] };
    }

    // Stream progress updates
    onUpdate?.({
      content: [{ type: "text", text: "Processing todo list..." }],
      details: { progress: 25 },
    });

    // Use withFileMutationQueue for safe file operations
    return withFileMutationQueue(resolve(ctx.cwd, "tasklist.json"), async () => {
      const current = await readFile(resolve(ctx.cwd, "tasklist.json"), "utf8");
      const tasks = JSON.parse(current) || [];

      if (params.action === "add" && params.text) {
        const newTask = {
          id: String(tasks.length + 1),
          text: params.text,
          completed: false
        };
        tasks.push(newTask);
        await writeFile(resolve(ctx.cwd, "tasklist.json"), 
          JSON.stringify(tasks, null, 2), "utf8");
        return {
          content: [{ type: "text", text: `Added task: ${newTask.text}` }],
          details: { added: newTask }
        };
      }
      else if (params.action === "list") {
        return {
          content: [{ type: "text", text: JSON.stringify(tasks, null, 2) }],
          details: { tasks }
        };
      }
      else if (params.action === "complete") {
        const task = tasks.find(t => t.id === params.text);
        if (task) {
          task.completed = true;
          await writeFile(resolve(ctx.cwd, "tasklist.json"), 
            JSON.stringify(tasks, null, 2), "utf8");
          return {
            content: [{ type: "text", text: `Completed: ${task.text}` }],
            details: { completed: task }
          };
        }
      }

      throw new Error(`Unknown action or missing required parameters`);
    });
  },

  // Optional: Custom rendering
  renderResult(result, options, theme, context) {
    return {
      type: "text" as const,
      text: result.details?.tasks ? `
        === Todo List ===
        ${result.details.tasks.map(t => 
          `${t.completed ? '✓' : '⬜ } ${t.text} #${t.id}`
        ).join('\n')}
      ` : JSON.stringify(result.details),
    };
  }
});
```

### 3. **Tool Operations**

```typescript
// ===== Operations interfaces =====

import { ReadOperations, WriteOperations, EditOperations } from "@mariozechner/pi-coding-agent";

type ReadOperations = {
  readFile: (path: string) => Promise<string> | null;
  access: (path: string) => Promise<void>;
};

type WriteOperations = {
  writeFile: (path: string, data: string) => Promise<void>;
};

type EditOperations = {
  editFile: (path: string, text: string) => Promise<void>;
};

// ===== Creating tools with custom operations =====

const createReadTool = (cwd: string, operations: ReadOperations) => {
  return {
    name: "read",
    label: "Read File",
    description: "Read file contents, supporting remote operations",
    async execute(toolCallId, params, signal, onUpdate, ctx) {
      if (signal?.aborted) return { content: [{ type: "text", text: "Cancelled" }] };

      const absolutePath = resolve(ctx.cwd, params.path);

      return operations.readFile(absolutePath)
        ?.catch(() => null)
        .then(content => content || "File not readable")
        .then(content => ({
          content: [{ type: "text", text: content }],
          details: { path: absolutePath }
        }));
    }
  };
};

// ===== Bash tools =====

const createBashTool = (cwd: string, operations: WriteOperations) => {
  return {
    name: "bash",
    label: "Execute Command",
    description: "Run bash commands in your terminal",
    async execute(toolCallId, params, signal, onUpdate, ctx) {
      if (signal?.aborted) return { content: [{ type: "text", text: "Cancelled" }] };

      return withFileMutationQueue(resolve(ctx.cwd, ".bash_history"), () =>
        execBashCommand(params.command, operations)
      );
    }
  };
};

const createLsTool = (cwd: string, operations: ReadOperations) => {
  return {
    name: "ls",
    label: "List Files",
