  promptGuidelines: [
    "Use this tool for todo planning instead of direct file edits",
    "Complete items by setting action to 'complete'",
    "Always track task progress using this tool"
  ],
  parameters: Type.Object({
    action: StringEnum(["add", "list", "complete", "clear"]),
    text: Type.Optional(Type.String()),
  }),

  async execute(toolCallId, params, signal, onUpdate, ctx) {
    // Handle cancellation
    if (signal?.aborted) {
      return { content: [{ type: "text", text: "Cancelled" }] };
    }

    // Stream progress updates
    onUpdate?.({
      content: [{ type: "text", text: "Processing todo list..." }],
      details: { progress: 25 },
    });

    // Use withFileMutationQueue for safe file operations
    return withFileMutationQueue(resolve(ctx.cwd, "tasklist.json"), async () => {
      const current = await readFile(resolve(ctx.cwd, "tasklist.json"), "utf8");
      const tasks = JSON.parse(current) || [];

      if (params.action === "add" && params.text) {
        const newTask = {
          id: String(tasks.length + 1),
          text: params.text,
          completed: false
        };
        tasks.push(newTask);
        await writeFile(resolve(ctx.cwd, "tasklist.json"), 
          JSON.stringify(tasks, null, 2), "utf8");
        return {
          content: [{ type: "text", text: `Added task: ${newTask.text}` }],
          details: { added: newTask }
        };
      }
      else if (params.action === "list") {
        return {
          content: [{ type: "text", text: JSON.stringify(tasks, null, 2) }],
          details: { tasks }
        };
      }
      else if (params.action === "complete") {
        const task = tasks.find(t => t.id === params.text);
        if (task) {
          task.completed = true;
          await writeFile(resolve(ctx.cwd, "tasklist.json"), 
            JSON.stringify(tasks, null, 2), "utf8");
          return {
            content: [{ type: "text", text: `Completed: ${task.text}` }],
            details: { completed: task }
          };
        }
      }

      throw new Error(`Unknown action or missing required parameters`);
    });
  },

  // Optional: Custom rendering
  renderResult(result, options, theme, context) {
    return {
      type: "text" as const,
      text: result.details?.tasks ? `
        === Todo List ===
        ${result.details.tasks.map(t => 
          `${t.completed ? '✓' : '⬜ } ${t.text} #${t.id}`
        ).join('\n')}
      ` : JSON.stringify(result.details),
    };
  }
});
```

