      const tasks = JSON.parse(current) || [];

      if (params.action === "add" && params.text) {
        const newTask = {
          id: String(tasks.length + 1),
          text: params.text,
          completed: false
        };
        tasks.push(newTask);
        await writeFile(resolve(ctx.cwd, "tasklist.json"), 
          JSON.stringify(tasks, null, 2), "utf8");
        return {
          content: [{ type: "text", text: `Added task: ${newTask.text}` }],
          details: { added: newTask }
        };
      }
      else if (params.action === "list") {
        return {
          content: [{ type: "text", text: JSON.stringify(tasks, null, 2) }],
          details: { tasks }
        };
      }
      else if (params.action === "complete") {
        const task = tasks.find(t => t.id === params.text);
        if (task) {
          task.completed = true;
          await writeFile(resolve(ctx.cwd, "tasklist.json"), 
            JSON.stringify(tasks, null, 2), "utf8");
          return {
            content: [{ type: "text", text: `Completed: ${task.text}` }],
            details: { completed: task }
          };
        }
      }

      throw new Error(`Unknown action or missing required parameters`);
    });
  },

