  if (seconds < 60) return `NOW`;
  const minutes = Math.floor(seconds / 60);
  const hour = Math.floor(diff / (1000 * 60 * 60));
  if (hour === 0) return `${minutes}m ago`;
  return `${hour}h ago`;
